/* ---------- derive metadata ---------- */
function abbr(n){return (n.replace(/[^A-Za-z0-9 ]/g,' ').trim().split(/\s+/).map(w=>w[0]).join('')||'X').slice(0,4).toUpperCase();}
FAM.forEach((f,i)=>{ f._i=i; f.abbr=abbr(f.n); f.d = f.d0 || (f.s==='mro' ? 'grainger' : 'voltfield'); f.search=(f.n+' '+f.kw+' '+f.c+' '+SECTORS[f.s].label).toLowerCase(); });

const SECTOR_TOTALS={}, CAT_TOTALS={}, SECTOR_CATS={};
FAM.forEach(f=>{
  SECTOR_TOTALS[f.s]=(SECTOR_TOTALS[f.s]||0)+f.ct;
  CAT_TOTALS[f.s]=CAT_TOTALS[f.s]||{}; CAT_TOTALS[f.s][f.c]=(CAT_TOTALS[f.s][f.c]||0)+f.ct;
  SECTOR_CATS[f.s]=SECTOR_CATS[f.s]||[]; if(!SECTOR_CATS[f.s].includes(f.c))SECTOR_CATS[f.s].push(f.c);
});
const GRAND_TOTAL=Object.values(SECTOR_TOTALS).reduce((a,b)=>a+b,0);
const DIST_TOTALS={};
FAM.forEach(f=>{DIST_TOTALS[f.d]=(DIST_TOTALS[f.d]||0)+f.ct;});

/* ---------- helpers ---------- */
const fmt=n=>n.toLocaleString('en-US');
function h(a,b){let x=((a>>>0)*2654435761 ^ (b>>>0)*40503)>>>0; x=(x^(x>>>13))>>>0; x=((x*1274126177)>>>0); return (x^(x>>>16))>>>0;}
function money(v,pu){
  let s;
  if(pu==='/W'||pu==='/kWh'){ s='$'+v.toFixed(v<1?3:2); }
  else if(v<10){ s='$'+v.toFixed(2); }
  else if(v<1000){ s='$'+v.toFixed(0); }
  else { s='$'+Math.round(v).toLocaleString('en-US'); }
  return s+(pu?` <small>${pu}</small>`:'');
}
function leadBadge(f){
  if(f.lw===0) return {t:f.sp||'In stock',c:'ok'};
  if(f.lw<=12) return {t:f.sp||(f.lw+' wk'),c:'ok'};
  if(f.lw<=52) return {t:f.sp||(f.lw+' wk'),c:'warn'};
  return {t:f.sp||(f.lw+' wk'),c:'crit'};
}
function skuCode(f,picks){return f.ax.map((axis,ai)=>{const o=axis.slice(1);const idx=Math.max(0,o.indexOf(picks[ai]));return idx.toString(36).toUpperCase();}).join('');}
function priceFor(f,picks){let t=0;f.ax.forEach((axis,ai)=>{const o=axis.slice(1);const idx=Math.max(0,o.indexOf(picks[ai]));t+=o.length>1?idx/(o.length-1):0.5;});t=f.ax.length?t/f.ax.length:0.5;return f.lo+t*(f.hi-f.lo);}
function configuredName(f,picks){const v=picks.slice(0,2).filter(Boolean).join(' ');return f.n+(v?' — '+v:'');}
function configuredPN(f,picks,chk){return `VF-${SECTORS[f.s].code}-${f.abbr}-${skuCode(f,picks)}${chk}`;}
function genSKU(f,i){
  const picks=f.ax.map((axis,ai)=>{const o=axis.slice(1); return o[h(i,ai+7)%o.length];});
  const chk=String((h(i,3)%90)+10);
  const pn=configuredPN(f,picks,chk);
  const name=configuredName(f,picks);
  const spec=f.ax.map((axis,ai)=>`${axis[0]}: ${picks[ai]}`).join('  ·  ');
  const price=priceFor(f,picks);
  return {pn,name,spec,price,picks,chk,f};
}
/* config <-> URL helpers (used by the shareable part page) */
function picksToParam(f,picks){return f.ax.map((axis,ai)=>Math.max(0,axis.slice(1).indexOf(picks[ai]))).join('.');}
function paramToPicks(f,param){const arr=(param||'').split('.');return f.ax.map((axis,ai)=>{const o=axis.slice(1);const idx=Math.max(0,Math.min(o.length-1,parseInt(arr[ai],10)||0));return o[idx];});}
const DIST_NAME={grainger:'Grainger',uline:'Uline',graybar:'Graybar',msc:'MSC Industrial',voltfield:'Voltfield Direct'};
